import { type ClassValue, clsx } from "clsx";
import { twMerge } from "tailwind-merge";

// cn — combine class names with clsx (conditional logic) plus tailwind-merge
// (deduplicates conflicting Tailwind utilities so the last-wins rule applies
// across props). The shadcn convention; customers can compose className
// props without inline string concatenation.
//
//   <div className={cn("p-2 bg-white", isActive && "bg-black", className)} />

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

import { layout, prepare } from "@chenglou/pretext";

export const DEFAULT_RESPONSIVE_TEXT_FONT_FAMILY =
  'ui-sans-serif, system-ui, sans-serif, "Apple Color Emoji", "Segoe UI Emoji", "Segoe UI Symbol", "Noto Color Emoji"';

export interface ResponsiveTextMetrics {
  heightPx: number;
  lineCount: number;
}

interface PrepareResponsiveTextOptions {
  fontFamily?: string;
  fontSizePx: number;
  fontWeight?: number | string;
  letterSpacingPx?: number;
  lineHeightPx: number;
  whiteSpace?: "normal" | "pre-wrap";
}

export function prepareResponsiveText(
  text: string,
  {
    fontFamily = DEFAULT_RESPONSIVE_TEXT_FONT_FAMILY,
    fontSizePx,
    fontWeight = 400,
    letterSpacingPx = 0,
    lineHeightPx,
    whiteSpace = "normal",
  }: PrepareResponsiveTextOptions,
): (maxWidthPx: number) => ResponsiveTextMetrics {
  const prepared = prepare(text, `${fontWeight} ${fontSizePx}px ${fontFamily}`, {
    letterSpacing: letterSpacingPx,
    whiteSpace,
  });

  return (maxWidthPx: number) => {
    if (maxWidthPx <= 0 || text.length === 0) {
      return { heightPx: lineHeightPx, lineCount: 1 };
    }

    const result = layout(prepared, maxWidthPx, lineHeightPx);
    const lineCount = Math.max(result.lineCount, 1);

    return {
      heightPx: Math.max(result.height, lineHeightPx),
      lineCount,
    };
  };
}

import * as React from "react";
import { type VariantProps, cva } from "class-variance-authority";

import { cn } from "@/lib/utils";

const buttonVariants = cva(
  "inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-md text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-[var(--color-caret)] focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50 [&_svg]:size-4 [&_svg]:shrink-0",
  {
    variants: {
      variant: {
        default: "bg-[var(--color-ink)] text-[var(--color-bg)] hover:bg-[var(--color-ink-80)]",
        outline:
          "border border-[var(--color-rule)] bg-[var(--color-paper)] text-[var(--color-ink)] hover:bg-[var(--color-paper-raised)]",
        ghost: "text-[var(--color-ink)] hover:bg-[var(--color-ink-5)]",
        destructive: "bg-red-600 text-white hover:bg-red-700",
      },
      size: {
        default: "h-10 px-4 py-2",
        sm: "h-8 rounded-md px-3 text-xs",
        lg: "h-11 rounded-md px-8",
        icon: "h-10 w-10",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  },
);

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof buttonVariants> {}

export const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
  ({ className, variant, size, ...props }, ref) => (
    <button ref={ref} className={cn(buttonVariants({ variant, size }), className)} {...props} />
  ),
);
Button.displayName = "Button";

export { buttonVariants };

